const body = $input.first().json.body || {};
const prompt = body.prompt || 'a beautiful landscape';
const aspectRatio = body.aspect_ratio || '1:1';
const refBase64 = body.refImageBase64 || null;
const refMime = body.refImageMime || null;

// Build parts array
const parts = [];

// Add reference image if provided
if (refBase64 && refMime) {
  parts.push({ inlineData: { mimeType: refMime, data: refBase64 } });
  parts.push({ text: `Generate an image based on the following prompt while using the provided reference image as visual guidance for style, composition, subject, or setting:\n\n${prompt}` });
} else {
  parts.push({ text: `Generate an image: ${prompt}` });
}

const requestBody = {
  contents: [{ parts: parts }],
  generationConfig: {
    responseModalities: ['IMAGE', 'TEXT'],
    temperature: 1,
    maxOutputTokens: 8192
  }
};

return [{ json: { requestBody: requestBody, prompt: prompt, aspectRatio: aspectRatio } }];

const data = $input.first().json;

// Check for HTTP error
if (data.error) {
  return [{ json: { 
    success: false, 
    error: data.error.message || 'Gemini API error',
    code: data.error.code || 500
  }}];
}

const candidates = data.candidates || [];
if (candidates.length > 0) {
  const parts = candidates[0].content?.parts || [];

  // Look for image data
  for (const part of parts) {
    if (part.inlineData) {
      const mimeType = part.inlineData.mimeType || 'image/png';
      const base64Data = part.inlineData.data;
      const dataUrl = `data:${mimeType};base64,${base64Data}`;

      return [{ json: { 
        success: true, 
        imageUrl: dataUrl,
        mimeType: mimeType,
        size: Math.round(base64Data.length / 1024) + 'KB'
      }}];
    }
  }

  // Check if only text was returned
  for (const part of parts) {
    if (part.text) {
      return [{ json: { 
        success: false, 
        error: 'Gemini returned text only, no image generated. Try a different prompt.',
        text: part.text.substring(0, 500)
      }}];
    }
  }
}

// Check for safety block
if (data.promptFeedback?.blockReason) {
  return [{ json: { 
    success: false, 
    error: 'Prompt blocked by safety filter: ' + data.promptFeedback.blockReason
  }}];
}

return [{ json: { success: false, error: 'No image in response' } }];
